import os,re,glob,json
roots=[os.path.expanduser('~/.agents/knowledge'), os.path.expanduser('~/Library/Application Support/app.dotagents/conversations')]
patterns=[r'youtube\.com/@[^\s\]"\')<>]+', r'youtube\.com/channel/[^\s\]"\')<>]+', r'youtube\.com/c/[^\s\]"\')<>]+', r'youtube\.com/user/[^\s\]"\')<>]+', r'@techfren', r'techfren']
rx=[re.compile(p,re.I) for p in patterns]
seen={}
for root in roots:
  if not os.path.isdir(root): continue
  files=[]
  for ext in ('*.md','*.json','*.txt'):
    files += glob.glob(os.path.join(root,'**',ext), recursive=True)
  files=sorted(files, key=lambda f: os.path.getmtime(f), reverse=True)[:4000]
  for f in files:
    try: txt=open(f,encoding='utf-8',errors='ignore').read(500000)
    except: continue
    for r in rx:
      for m in r.findall(txt):
        seen.setdefault(m,[]).append(f)
for m,fs in sorted(seen.items(), key=lambda kv: (-len(kv[1]), kv[0]))[:50]:
  print(len(fs), m)
  print(' ', fs[0])
PY

